// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/token/ERC20/ERC20.sol";
import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";

contract RialoToken is ERC20, Ownable, ReentrancyGuard {
    uint256 public constant FAUCET_AMOUNT = 1000 * 10 ** 18;
    uint256 public constant COOLDOWN = 24 hours;
    uint256 public constant MAX_SUPPLY = 1_000_000_000 * 10 ** 18;

    mapping(address => uint256) public lastFaucetClaim;

    event FaucetClaimed(address indexed user, uint256 amount, uint256 timestamp);

    constructor(address initialOwner) ERC20("Rialo Token", "RLO") Ownable(initialOwner) {
        _mint(initialOwner, 900_000_000 * 10 ** 18);
        _mint(address(this), 100_000_000 * 10 ** 18);
    }

    function claimFaucet() external nonReentrant {
        require(block.timestamp >= lastFaucetClaim[msg.sender] + COOLDOWN, "RLO: Cooldown not finished");
        require(balanceOf(address(this)) >= FAUCET_AMOUNT, "RLO: Faucet empty");
        lastFaucetClaim[msg.sender] = block.timestamp;
        _transfer(address(this), msg.sender, FAUCET_AMOUNT);
        emit FaucetClaimed(msg.sender, FAUCET_AMOUNT, block.timestamp);
    }

    function getNextClaimTime(address user) external view returns (uint256) {
        if (lastFaucetClaim[user] == 0) return 0;
        uint256 next = lastFaucetClaim[user] + COOLDOWN;
        return next > block.timestamp ? next : 0;
    }

    function refillFaucet(uint256 amount) external onlyOwner {
        require(totalSupply() + amount <= MAX_SUPPLY, "RLO: Exceeds max supply");
        _mint(address(this), amount);
    }

    function mintTo(address to, uint256 amount) external onlyOwner {
        require(totalSupply() + amount <= MAX_SUPPLY, "RLO: Exceeds max supply");
        _mint(to, amount);
    }
}

contracts/Staking.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";
import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";

contract Staking is Ownable, ReentrancyGuard {
    using SafeERC20 for IERC20;

    IERC20 public immutable rewardToken; // RLO

    struct PoolInfo {
        IERC20 token;
        uint256 aprBps;       // basis points, e.g. 1000 = 10%
        uint256 totalStaked;
        bool active;
    }

    struct UserInfo {
        uint256 amount;
        uint256 rewardDebt;
        uint256 lastUpdateTime;
    }

    PoolInfo[] public pools;
    // poolId => user => UserInfo
    mapping(uint256 => mapping(address => UserInfo)) public userInfo;

    event Staked(address indexed user, uint256 indexed pid, uint256 amount);
    event Withdrawn(address indexed user, uint256 indexed pid, uint256 amount);
    event RewardClaimed(address indexed user, uint256 indexed pid, uint256 reward);
    event PoolAdded(uint256 indexed pid, address token, uint256 aprBps);

    constructor(address _rewardToken, address initialOwner) Ownable(initialOwner) {
        rewardToken = IERC20(_rewardToken);
    }

    function addPool(address _token, uint256 _aprBps) external onlyOwner {
        pools.push(PoolInfo({
            token: IERC20(_token),
            aprBps: _aprBps,
            totalStaked: 0,
            active: true
        }));
        emit PoolAdded(pools.length - 1, _token, _aprBps);
    }

    function setPoolAPR(uint256 pid, uint256 _aprBps) external onlyOwner {
        pools[pid].aprBps = _aprBps;
    }

    function pendingReward(uint256 pid, address _user) public view returns (uint256) {
        UserInfo storage user = userInfo[pid][_user];
        if (user.amount == 0) return user.rewardDebt;
        PoolInfo storage pool = pools[pid];
        uint256 elapsed = block.timestamp - user.lastUpdateTime;
        uint256 reward = (user.amount * pool.aprBps * elapsed) / (10000 * 365 days);
        return user.rewardDebt + reward;
    }

    function stake(uint256 pid, uint256 amount) external nonReentrant {
        require(pid < pools.length, "Staking: Invalid pool");
        require(pools[pid].active, "Staking: Pool not active");
        require(amount > 0, "Staking: Amount must be > 0");

        PoolInfo storage pool = pools[pid];
        UserInfo storage user = userInfo[pid][msg.sender];

        // Accumulate pending reward before updating
        if (user.amount > 0) {
            uint256 pending = pendingReward(pid, msg.sender);
            user.rewardDebt = pending;
        }

        pool.token.safeTransferFrom(msg.sender, address(this), amount);
        user.amount += amount;
        user.lastUpdateTime = block.timestamp;
        pool.totalStaked += amount;

        emit Staked(msg.sender, pid, amount);
    }

    function withdraw(uint256 pid, uint256 amount) external nonReentrant {
        require(pid < pools.length, "Staking: Invalid pool");
        UserInfo storage user = userInfo[pid][msg.sender];
        require(user.amount >= amount, "Staking: Insufficient staked");

        PoolInfo storage pool = pools[pid];

        // Accumulate reward
        user.rewardDebt = pendingReward(pid, msg.sender);
        user.lastUpdateTime = block.timestamp;
        user.amount -= amount;
        pool.totalStaked -= amount;

        pool.token.safeTransfer(msg.sender, amount);
        emit Withdrawn(msg.sender, pid, amount);
    }

    function claimReward(uint256 pid) external nonReentrant {
        require(pid < pools.length, "Staking: Invalid pool");
        UserInfo storage user = userInfo[pid][msg.sender];

        uint256 reward = pendingReward(pid, msg.sender);
        require(reward > 0, "Staking: No reward");

        user.rewardDebt = 0;
        user.lastUpdateTime = block.timestamp;

        rewardToken.safeTransfer(msg.sender, reward);
        emit RewardClaimed(msg.sender, pid, reward);
    }

    function claimAllRewards() external nonReentrant {
        uint256 totalReward = 0;
        for (uint256 pid = 0; pid < pools.length; pid++) {
            UserInfo storage user = userInfo[pid][msg.sender];
            uint256 reward = pendingReward(pid, msg.sender);
            if (reward > 0) {
                user.rewardDebt = 0;
                user.lastUpdateTime = block.timestamp;
                totalReward += reward;
                emit RewardClaimed(msg.sender, pid, reward);
            }
        }
        require(totalReward > 0, "Staking: No rewards to claim");
        rewardToken.safeTransfer(msg.sender, totalReward);
    }

    function poolLength() external view returns (uint256) {
        return pools.length;
    }

    function depositRewards(uint256 amount) external onlyOwner {
        rewardToken.safeTransferFrom(msg.sender, address(this), amount);
    }
}

contracts/Swap.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";
import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";

contract Swap is Ownable, ReentrancyGuard {
    using SafeERC20 for IERC20;
    uint256 public constant FEE_BPS = 30;
    mapping(address => uint256) public tokenPrice;
    mapping(address => uint256) public liquidity;
    address public constant ETH_ADDRESS = address(0);
    event LiquidityAdded(address indexed token, uint256 amount);
    event LiquidityRemoved(address indexed token, uint256 amount);
    event SwappedETHToToken(address indexed user, address indexed token, uint256 ethIn, uint256 tokenOut);
    event SwappedTokenToETH(address indexed user, address indexed token, uint256 tokenIn, uint256 ethOut);
    event SwappedTokenToToken(address indexed user, address indexed tokenIn, address indexed tokenOut, uint256 amountIn, uint256 amountOut);
    constructor(address initialOwner) Ownable(initialOwner) {}
    function setTokenPrice(address token, uint256 priceUSD18) external onlyOwner { tokenPrice[token] = priceUSD18; }
    function getAmountOut(address tokenIn, address tokenOut, uint256 amountIn) public view returns (uint256 amountOut, uint256 fee) {
        uint256 priceIn = tokenIn == ETH_ADDRESS ? tokenPrice[ETH_ADDRESS] : tokenPrice[tokenIn];
        uint256 priceOut = tokenOut == ETH_ADDRESS ? tokenPrice[ETH_ADDRESS] : tokenPrice[tokenOut];
        require(priceIn > 0 && priceOut > 0, "Swap: Price not set");
        fee = (amountIn * FEE_BPS) / 10000;
        amountOut = ((amountIn - fee) * priceIn) / priceOut;
    }
    function swapETHToToken(address tokenOut, uint256 minAmountOut) external payable nonReentrant {
        require(msg.value > 0, "Swap: No ETH sent");
        require(tokenOut != ETH_ADDRESS, "Swap: Use ETH directly");
        (uint256 amountOut, ) = getAmountOut(ETH_ADDRESS, tokenOut, msg.value);
        require(amountOut >= minAmountOut, "Swap: Slippage too high");
        require(IERC20(tokenOut).balanceOf(address(this)) >= amountOut, "Swap: Insufficient liquidity");
        liquidity[ETH_ADDRESS] += msg.value;
        liquidity[tokenOut] -= amountOut;
        IERC20(tokenOut).safeTransfer(msg.sender, amountOut);
        emit SwappedETHToToken(msg.sender, tokenOut, msg.value, amountOut);
    }
    function swapTokenToETH(address tokenIn, uint256 amountIn, uint256 minAmountOut) external nonReentrant {
        require(amountIn > 0, "Swap: Amount must be > 0");
        require(tokenIn != ETH_ADDRESS, "Swap: Invalid tokenIn");
        (uint256 ethOut, ) = getAmountOut(tokenIn, ETH_ADDRESS, amountIn);
        require(ethOut >= minAmountOut, "Swap: Slippage too high");
        require(address(this).balance >= ethOut, "Swap: Insufficient ETH liquidity");
        IERC20(tokenIn).safeTransferFrom(msg.sender, address(this), amountIn);
        liquidity[tokenIn] += amountIn;
        liquidity[ETH_ADDRESS] -= ethOut;
        (bool success, ) = msg.sender.call{value: ethOut}("");
        require(success, "Swap: ETH transfer failed");
        emit SwappedTokenToETH(msg.sender, tokenIn, amountIn, ethOut);
    }
    function swapTokenToToken(address tokenIn, address tokenOut, uint256 amountIn, uint256 minAmountOut) external nonReentrant {
        require(amountIn > 0, "Swap: Amount must be > 0");
        require(tokenIn != tokenOut, "Swap: Same token");
        require(tokenIn != ETH_ADDRESS && tokenOut != ETH_ADDRESS, "Swap: Use ETH functions");
        (uint256 amountOut, ) = getAmountOut(tokenIn, tokenOut, amountIn);
        require(amountOut >= minAmountOut, "Swap: Slippage too high");
        require(IERC20(tokenOut).balanceOf(address(this)) >= amountOut, "Swap: Insufficient liquidity");
        IERC20(tokenIn).safeTransferFrom(msg.sender, address(this), amountIn);
        liquidity[tokenIn] += amountIn;
        liquidity[tokenOut] -= amountOut;
        IERC20(tokenOut).safeTransfer(msg.sender, amountOut);
        emit SwappedTokenToToken(msg.sender, tokenIn, tokenOut, amountIn, amountOut);
    }
    function addLiquidityETH() external payable onlyOwner { require(msg.value > 0, "Swap: No ETH"); liquidity[ETH_ADDRESS] += msg.value; emit LiquidityAdded(ETH_ADDRESS, msg.value); }
    function addLiquidity(address token, uint256 amount) external onlyOwner { IERC20(token).safeTransferFrom(msg.sender, address(this), amount); liquidity[token] += amount; emit LiquidityAdded(token, amount); }
    function removeLiquidity(address token, uint256 amount) external onlyOwner {
        require(liquidity[token] >= amount, "Swap: Insufficient liquidity");
        liquidity[token] -= amount;
        if (token == ETH_ADDRESS) { (bool success, ) = owner().call{value: amount}(""); require(success, "Swap: ETH transfer failed"); }
        else { IERC20(token).safeTransfer(owner(), amount); }
        emit LiquidityRemoved(token, amount);
    }
    receive() external payable { liquidity[ETH_ADDRESS] += msg.value; }
}

